import random

def generate_dna(length):
    return ''.join(random.choice('ACGT') for _ in range(length))

sequences = []
for i in range(1, 25):
    seq_id = f'seq{i}'
    # Ensure some sequences have ORFs
    if i % 2 == 0:
        # Start + middle + stop
        dna = generate_dna(50) + 'ATG' + generate_dna(120) + 'TAA' + generate_dna(50)
    else:
        dna = generate_dna(300)
    sequences.append((seq_id, dna))

import os
os.makedirs('workspace', exist_ok=True)
with open('workspace/sequences.fasta', 'w') as f:
    for seq_id, dna in sequences:
        f.write(f'>{seq_id}\n{dna}\n')
"
